"""Debug tool routes: SPARQL query console and event console."""

from fastapi import APIRouter, Depends, Request

from app.auth.dependencies import get_current_user, require_role
from app.auth.models import User

router = APIRouter(tags=["debug"])


@router.get("/sparql")
async def sparql_page(request: Request, user: User = Depends(require_role("owner"))):
    """Render the SPARQL query console. Owner role required."""
    templates = request.app.state.templates
    return templates.TemplateResponse(
        request, "debug/sparql.html", {"active_page": "sparql", "user": user}
    )


@router.get("/events")
async def event_console_page(request: Request, user: User = Depends(get_current_user)):
    """Render the event console (command executor + live event log)."""
    templates = request.app.state.templates
    context = {"active_page": "events", "user": user}
    if request.headers.get("HX-Request"):
        return templates.TemplateResponse(
            request, "debug/event_console.html", context, block_name="content"
        )
    return templates.TemplateResponse(request, "debug/event_console.html", context)

server {
    listen 80;
    server_name localhost;

    # Preserve percent-encoded slashes (%2F) in proxied URIs.
    # Without this, nginx decodes %2F to / and then merge_slashes collapses
    # // to /, which breaks IRIs like https%3A%2F%2F... in URL path segments.
    merge_slashes off;

    # Static CSS assets served directly by nginx (no-cache for dev)
    location /css/ {
        root /usr/share/nginx/html;
        add_header Cache-Control "no-store, no-cache, must-revalidate";
        try_files $uri =404;
    }

    # Static JS assets served directly by nginx (no-cache for dev)
    location /js/ {
        root /usr/share/nginx/html;
        add_header Cache-Control "no-store, no-cache, must-revalidate";
        try_files $uri =404;
    }

    # Auth pages served as static HTML by nginx
    location = /setup.html {
        root /usr/share/nginx/html;
        try_files $uri =404;
    }

    location = /login.html {
        root /usr/share/nginx/html;
        try_files $uri =404;
    }

    location = /invite.html {
        root /usr/share/nginx/html;
        try_files $uri =404;
    }

    # Proxy API requests to FastAPI backend (with cookie forwarding for auth)
    location /api/ {
        proxy_pass http://api:8000/api/;
        proxy_set_header Host $http_host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Cookie $http_cookie;
        proxy_pass_header Set-Cookie;
    }

    # LLM Streaming Proxy — SSE endpoint, must be before catch-all location /
    # proxy_buffering off prevents nginx from accumulating the full response
    # before forwarding; required for streaming/SSE to work correctly.
    location /browser/llm/chat/stream {
        proxy_pass http://api:8000/browser/llm/chat/stream;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Cookie $http_cookie;
        proxy_pass_header Set-Cookie;

        # SSE-specific configuration
        proxy_buffering off;
        proxy_http_version 1.1;
        proxy_read_timeout 300s;
        proxy_send_timeout 300s;
        proxy_set_header Cache-Control "no-cache";
        proxy_set_header Connection "keep-alive";
        add_header X-Accel-Buffering "no";
    }

    # WebDAV VFS endpoint — proxied to FastAPI/wsgidav
    # Must pass Authorization header (Basic auth for native OS WebDAV clients)
    # and WebDAV protocol headers (Depth, Destination, Overwrite).
    location /dav/ {
        proxy_pass http://api:8000/dav/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # Pass Basic auth credentials to wsgidav (do NOT strip Authorization)
        proxy_set_header Authorization $http_authorization;
        proxy_pass_header Authorization;

        # WebDAV protocol headers
        proxy_set_header Depth $http_depth;
        proxy_set_header Destination $http_destination;
        proxy_set_header Overwrite $http_overwrite;

        # Extended timeouts for PROPFIND on large directories
        proxy_read_timeout 300s;
        proxy_send_timeout 300s;

        # Allow large PROPFIND responses
        proxy_buffering on;
        client_max_body_size 10m;
    }

    # Lint SSE Streaming — real-time validation event push
    # Must be before catch-all location / to match specifically.
    # proxy_buffering off prevents nginx from accumulating the full response.
    location /api/lint/stream {
        proxy_pass http://api:8000/api/lint/stream;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Cookie $http_cookie;
        proxy_pass_header Set-Cookie;
        proxy_buffering off;
        proxy_http_version 1.1;
        proxy_read_timeout 86400s;
        proxy_send_timeout 86400s;
        proxy_set_header Cache-Control "no-cache";
        proxy_set_header Connection "keep-alive";
        add_header X-Accel-Buffering "no";
    }

    # Obsidian vault upload — unlimited size, no buffering
    location /browser/import/upload {
        client_max_body_size 0;
        proxy_request_buffering off;
        proxy_pass http://api:8000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Cookie $http_cookie;
        proxy_pass_header Set-Cookie;
    }

    # Obsidian scan SSE stream — no buffering for real-time events
    location ~ /browser/import/scan/.*/stream$ {
        proxy_pass http://api:8000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header Cookie $http_cookie;
        proxy_pass_header Set-Cookie;
        proxy_set_header Connection '';
        proxy_http_version 1.1;
        chunked_transfer_encoding off;
        proxy_buffering off;
        proxy_cache off;
        add_header X-Accel-Buffering no;
    }

    # All other routes proxied to FastAPI for template rendering
    location / {
        proxy_pass http://api:8000/;
        proxy_set_header Host $http_host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header Cookie $http_cookie;
        proxy_pass_header Set-Cookie;
    }
}
